mapper.select:
SELECT id, steering_id, version, title, content, tags, keywords, change_log, status, created_by, created_at, updated_at
FROM steering_version
WHERE steering_id = #{steeringId}
  AND version = #{version}

mapper.update:
UPDATE steering_version
SET status = #{toStatus}, updated_at = NOW()
WHERE steering_id = #{steeringId}
  AND status = #{fromStatus}

mapper.select:
SELECT id, steering_id, version, title, content, tags, keywords, change_log, status, created_by, created_at, updated_at
FROM steering_version
WHERE steering_id = #{steeringId}
  AND status = #{status}
LIMIT 1

SELECT id, steering_id, version, title, content, tags, keywords, change_log, status, created_by, created_at, updated_at
FROM steering_version
WHERE steering_id = #{steeringId}
ORDER BY version DESC
LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE steering_version
SET status = #{newStatus}, updated_at = NOW()
